def calculate_average_effectiveness(feedback, treatment_name):
    # Filter the feedback to include only those with the specified treatment
    treatment_feedback = [
        patient["treatments"][treatment_name] for patient in feedback if treatment_name in patient["treatments"]
    ]

    # Calculate the average effectiveness
    if not treatment_feedback:
        return 0.0
    else:
        average = sum(treatment_feedback) / len(treatment_feedback)
        return round(average, 2)
